INSERT INTO "produtos" ("id","nome","categoria","categoriaSlug","imagemPrincipal","imagens","descricao","destaque","relevancia","created_at") VALUES(1,'Armário para Sala','Armários','armario','/images/produtos/armario/armario-sala.jpeg','["/images/produtos/armario/armario-sala.jpeg"]','Armário planejado sob medida, ideal para a organização de itens e otimização de espaço na sala de estar, garantindo um visual minimalista e elegante.',0,4,'2026-05-01 02:58:33');
INSERT INTO "produtos" ("id","nome","categoria","categoriaSlug","imagemPrincipal","imagens","descricao","destaque","relevancia","created_at") VALUES(2,'Armário Banheiro Planejado','Banheiros','banheiro','/images/produtos/banheiro/banheiro-1.jpg','["/images/produtos/banheiro/banheiro-1.jpg","/images/produtos/banheiro/banheiro-2.jpg","/images/produtos/banheiro/banheiro-3.jpg"]','Conjunto completo de marcenaria para banheiro planejado, composto por armários de excelente divisória e resistente à umidade típica do ambiente.',0,3,'2026-05-01 02:58:33');
INSERT INTO "produtos" ("id","nome","categoria","categoriaSlug","imagemPrincipal","imagens","descricao","destaque","relevancia","created_at") VALUES(3,'Área Gourmet Planejada','Cozinhas','cozinha','/images/produtos/cozinha/area-gourmet.jpg','["/images/produtos/cozinha/area-gourmet.jpg"]','Projeto focado em áreas gourmet, perfeitamente alinhado com churrasqueiras e áreas de lazer, proporcionando funcionalidade e beleza nas suas recepções.',0,4,'2026-05-01 02:58:33');
INSERT INTO "produtos" ("id","nome","categoria","categoriaSlug","imagemPrincipal","imagens","descricao","destaque","relevancia","created_at") VALUES(4,'Cozinha Planejada Completa','Cozinhas','cozinha','/images/produtos/cozinha/armario&movel-cozinha-.jpg','["/images/produtos/cozinha/armario&movel-cozinha-.jpg"]','Conjunto de móveis para bancada e pia da cozinha. Acabamento moderno que facilita a limpeza no dia-a-dia.',1,3,'2026-05-01 02:58:33');
