INSERT INTO "produtos" ("id","nome","categoria","categoriaSlug","imagemPrincipal","imagens","descricao","destaque","relevancia","created_at") VALUES(6,'Cozinha Planejada Moderna','Cozinhas','cozinha','/images/produtos/cozinha/armario-cozinha-1.jpg','["/images/produtos/cozinha/armario-cozinha-1.jpg","/images/produtos/cozinha/armario-cozinha-2.jpg"]','Torre de armários projetada para aproveitamento verticalizado do ambiente da cozinha. Estante generosa em litragem e nichos dedicados a micro-ondas ou forno.',0,5,'2026-05-01 02:58:33');
