INSERT INTO "produtos" ("id","nome","categoria","categoriaSlug","imagemPrincipal","imagens","descricao","destaque","relevancia","created_at") VALUES(8,'Escritório Corporativo e Home Office','Escritórios','escritorio','/images/produtos/escritorio/escritorio.jpg','["/images/produtos/escritorio/escritorio.jpg"]','Estação de trabalho milimetricamente desenhada visando conforto ergonômico, espaçamento de monitores e armazenamento essencial de documentos em gaveteiros fluidos.',1,4,'2026-05-01 02:58:33');
