INSERT INTO "produtos" ("id","nome","categoria","categoriaSlug","imagemPrincipal","imagens","descricao","destaque","relevancia","created_at") VALUES(13,'Mobiliário Comercial para Salão','Projetos Comerciais','planejados-comercio','/images/produtos/planejados comercio/salao-1.jpg','["/images/produtos/planejados comercio/salao-1.jpg","/images/produtos/planejados comercio/salao-2.jpg","/images/produtos/planejados comercio/salao-3.jpg"]','Conjunto corporativo robusto focado em Salões e Estéticas. Projetado para aguentar uso contínuo de clientes, fluxo intenso e fácil isolamento de áreas úmidas das cubas.',1,5,'2026-05-01 02:58:33');
